mapper.select:
select from cook_ai_image_recognition_logs r left join cook_users u on u.id = r.user_id and u.deleted_at is null left join cook_ai_models am on am.id = r.model_id where r.user_id = #{userId} and r.deleted_at is null
and r.status = #{status}
order by r.created_at desc, r.id desc

select from cook_ai_image_recognition_logs r left join cook_users u on u.id = r.user_id and u.deleted_at is null left join cook_ai_models am on am.id = r.model_id where r.deleted_at is null
and r.status = #{status}
and r.user_id = #{userId}
and (r.recognized_name like concat('%', #{keyword}, '%') or u.nickname like concat('%', #{keyword}, '%'))
order by r.created_at desc, r.id desc

mapper.insert:
insert into cook_ai_image_recognition_logs (
    user_id, model_id, image_media_id, image_url, result_json, nutrition_json,
    candidates_json, response_time_ms, error_message, status, recognized_name,
    confidence, calories, suggestion
) values (
    #{userId}, #{modelId}, #{imageMediaId}, #{imageUrl}, #{resultJson}, #{nutritionJson},
    #{candidatesJson}, #{responseTimeMs}, #{errorMessage}, #{status}, #{recognizedName},
    #{confidence}, #{calories}, #{suggestion}
)

mapper.update:
update cook_ai_image_recognition_logs
set deleted_at = current_timestamp,
    updated_at = current_timestamp
where id = #{id}
  and user_id = #{userId}
  and deleted_at is null
